#include<bits/stdc++.h>
using namespace std;

int v[100005], t[100005], nex[100005], mv[100005], vis[100005],answer[100005];
int dfs(int x) {
    if (answer[x] != 0) return answer[x];
	if (vis[x]) return x;
	vis[x] = 1;
	int xx = v[x], ans = 0;
	while (xx != 0) {
        ans = max(ans,dfs(t[xx]));
		xx = nex[xx];
	}
	vis[x] = 0;
    answer[x]=max(ans,x);
	return max(x,ans);
}
int main() {
	int n, m;
	cin >> n >> m;

	for (int i = 1; i <= m; i++) {
		int x, y;
		cin >> x >> y;
		nex[i] = v[x];
		v[x] = i;
		t[i] = y;
	}
	for (int i = 1; i <= n; i++) {
		cout << dfs(i) << " ";
	}
	return 0;
}
